import unittest

class TestSolution(unittest.TestCase):
    def test_basic_two_word(self):
        self.assertEqual(screaming_to_camel(["FIRST_NAME", "LAST_NAME"]), ["firstName", "lastName"])

    def test_three_word(self):
        self.assertEqual(screaming_to_camel(["DATE_OF_BIRTH"]), ["dateOfBirth"])

    def test_single_word(self):
        self.assertEqual(screaming_to_camel(["ID", "STATUS"]), ["id", "status"])

    def test_hidden_empty_list(self):
        self.assertEqual(screaming_to_camel([]), [])

    def test_hidden_long_chain(self):
        self.assertEqual(screaming_to_camel(["USER_EMAIL_ADDRESS"]), ["userEmailAddress"])

    def test_hidden_single_letters(self):
        self.assertEqual(screaming_to_camel(["A_B_C"]), ["aBC"])

    def test_hidden_mixed_list(self):
        result = screaming_to_camel(["CREATED_AT", "UPDATED_AT", "NAME"])
        self.assertEqual(result, ["createdAt", "updatedAt", "name"])

    def test_hidden_single_element(self):
        self.assertEqual(screaming_to_camel(["TOTAL_AMOUNT_DUE"]), ["totalAmountDue"])

    def test_hidden_many_columns(self):
        inp = ["ORDER_ID", "CUSTOMER_NAME", "SHIPPING_ADDRESS", "ZIP_CODE", "COUNTRY"]
        expected = ["orderId", "customerName", "shippingAddress", "zipCode", "country"]
        self.assertEqual(screaming_to_camel(inp), expected)

